+            };
+          case 'data_type':
+            return {
+              object_id: i.object_id,
+              fields: {
+                id: safeValue(f.id),
+                container_id: safeValue(f.container_id),
+                external_id: f.external_id,
+                name: f.name,
+                description: f.description,
+                content: f.content,
+                schemas: f.schemas,
+                sequence_index: f.sequence_index,
+                external_index: f.external_index,
+                last_data_item_id: safeValue(f.last_data_item_id),
+                prev_id: safeValue(f.prev_id),
+              },
+            };
+          case 'data_item':
+            return {
+              object_id: i.object_id,
+              fields: {
+                id: safeValue(f.id),
+                container_id: safeValue(f.container_id),
+                data_type_id: safeValue(f.data_type_id),
+                external_id: f.external_id,
+                creator: f.creator,
+                name: f.name,
+                description: f.description,
+                content: f.content,
+                sequence_index: f.sequence_index,
+                external_index: f.external_index,
+                prev_id: safeValue(f.prev_id),
+                prev_data_type_item_id: safeValue(f.prev_data_type_item_id),
+              },
+            };
+          default:
+            return { object_id: i.object_id, fields: f };
