+import { useState } from 'react';
+import { ItemsTable } from './ItemsTable.tsx';
+import type { Item, RawItem } from '../Types.tsx';
+
+interface ItemsLoaderProps {
+  containerId: string;
+  type: 'owner' | 'child' | 'data_type' | 'data_item';
+}
+
+export function ItemsLoader({ containerId, type }: ItemsLoaderProps) {
+  const [items, setItems] = useState<Item[]>([]);
+  const [loading, setLoading] = useState(false);
+  const [error, setError] = useState<string | null>(null);
+
+  const normalizeItem = (raw: RawItem): Item => {
+    const f: Record<string, any> = {};
+
+    for (const key in raw.fields) {
+      const v = raw.fields[key];
+      if (v && typeof v === 'object' && 'id' in v) {
+        f[key] = v.id;
+      } else if (v === null || v === undefined) {
+        f[key] = '-';
+      } else {
+        f[key] = v;
+      }
+    }
+
+    return {
+      object_id: raw.object_id,
+      fields: f,
+    };
+  };
+
+  const loadItems = async () => {
+    setLoading(true);
+    setError(null);
+
+    try {
+      const res = await fetch(
+        `http://localhost:8084/api/items?containerId=${containerId}&type=${type}`
+      );
+      if (!res.ok) throw new Error(`HTTP ${res.status}`);
+
+      const data: { items?: RawItem[] } = await res.json();
+      const rawItems = data.items ?? [];
+
+      const normalized: Item[] = rawItems.map(normalizeItem);
+      setItems(normalized);
+    } catch (err: any) {
+      console.error('Failed to load items', err);
+      setError(err.message || 'Failed to load items');
+      setItems([]);
+    } finally {
+      setLoading(false);
+    }
+  };
+
+  return (
+    <div style={{ marginTop: 20 }}>
+      <button
+        className="btn btn-secondary"
+        onClick={loadItems}
+        disabled={loading}
+      >
+        {loading ? 'Loading…' : 'Load Items'}
+      </button>
+
+      <div style={{ marginTop: 10 }}>
+        <ItemsTable containerId={containerId} items={items} error={error ?? undefined} />
+      </div>
+    </div>
+  );
+}

