import { useState } from 'react';
import { ItemsTable } from './ItemsTable.tsx'; // adjust path
// ItemsTable.tsx
import type { Item } from '../Types.tsx';
interface ItemsLoaderProps {
  containerId: string;
  type: 'owner' | 'child' | 'data_type' | 'data_item';
}

export function ItemsLoader({ containerId, type }: ItemsLoaderProps) {
  const [items, setItems] = useState<Item[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadItems = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(
        `http://localhost:8084/api/items?containerId=${containerId}&type=${type}`
      );
      if (!res.ok) throw new Error(`HTTP ${res.status}`);

const data: {
  container_id: string;
  type: string;
  count: number;
  items?: Item[];
} = await res.json();

// Use empty array if items is missing
const rawItems = data.items ?? [];

const normalized: Item[] = rawItems.map((i) => {
  const f = i.fields;
  switch (type) {
    case 'owner':
      return {
        object_id: i.object_id,
        fields: {
          id: f.id?.id ?? f.id,
          addr: f.addr,
          role: f.role,
          removed: f.removed,
          sequence_index: f.sequence_index,
        },
      };
    case 'child':
      return {
        object_id: i.object_id,
        fields: {
          id: f.id?.id ?? f.id,
          container_parent_id: f.container_parent_id?.id ?? f.container_parent_id,
          container_child_id: f.container_child_id?.id ?? f.container_child_id,
          external_id: f.external_id,
          name: f.name,
          description: f.description,
          content: f.content,
          sequence_index: f.sequence_index,
          prev_id: f.prev_id?.id ?? f.prev_id,
        },
      };
    case 'data_type':
      return {
        object_id: i.object_id,
        fields: {
          id: f.id?.id ?? f.id,
          container_id: f.container_id?.id ?? f.container_id,
          external_id: f.external_id,
          name: f.name,
          description: f.description,
          content: f.content,
          schemas: f.schemas,
          sequence_index: f.sequence_index,
          external_index: f.external_index,
          last_data_item_id: f.last_data_item_id?.id ?? f.last_data_item_id,
          prev_id: f.prev_id?.id ?? f.prev_id,
        },
      };
    case 'data_item':
      return {
        object_id: i.object_id,
        fields: {
          id: f.id?.id ?? f.id,
          container_id: f.container_id?.id ?? f.container_id,
          data_type_id: f.data_type_id?.id ?? f.data_type_id,
          external_id: f.external_id,
          creator: f.creator,
          name: f.name,
          description: f.description,
          content: f.content,
          sequence_index: f.sequence_index,
          external_index: f.external_index,
          prev_id: f.prev_id?.id ?? f.prev_id,
          prev_data_type_item_id:
            f.prev_data_type_item_id?.id ?? f.prev_data_type_item_id,
        },
      };
    default:
      return { object_id: i.object_id, fields: f };
  }
});

setItems(normalized);

    } catch (err: any) {
      console.error('Failed to load items', err);
      setError(err.message || 'Failed to load items');
      setItems([]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ marginTop: 20 }}>
      <button className="btn secondary" onClick={loadItems} disabled={loading}>
        {loading ? 'Loading…' : 'Load Items'}
      </button>

      <div style={{ marginTop: 10 }}>
        <ItemsTable containerId={containerId} items={items} error={error ?? undefined} />
      </div>
    </div>
  );
}
